## 3. Build & install (CMake + setuptools)

Create a `setup.py` in the same directory:

```python
# --------------------------------------------------------------
#  setup.py
# --------------------------------------------------------------
import pathlib, sys, os
from setuptools import setup, Extension
from setuptools.command.build_ext import build_ext

class CMakeExtension(Extension):
    def __init__(self, name):
        super().__init__(name, sources=[])

class CMakeBuild(build_ext):
    def run(self):
        for ext in self.extensions:
            self.build_cmake(ext)

    def build_cmake(self, ext):
        import subprocess, json, shutil
        cwd = pathlib.Path(__file__).parent.resolve()
        build_dir = cwd / "build"
        build_dir.mkdir(exist_ok=True)

        cmake_args = [
            f"-DCMAKE_LIBRARY_OUTPUT_DIRECTORY={build_dir}",
            f"-DPYTHON_EXECUTABLE={sys.executable}",
        ]

        subprocess.check_call(["cmake", str(cwd)] + cmake_args, cwd=build_dir)
        subprocess.check_call(["cmake", "--build", "."], cwd=build_dir)

        # copy the generated .so into the package directory
        libname = "blockscipy" + (".pyd" if os.name == "nt" else ".so")
        src = build_dir / libname
        dst = pathlib.Path(self.get_ext_fullpath(ext.name))
        dst.parent.mkdir(parents=True, exist_ok=True)
        shutil.copyfile(src, dst)

setup(
    name="blockscipy",
    version="0.1.0",
    author="Your Name",
    description="Fast per‑block callbacks for BlockSci",
    ext_modules=[CMakeExtension("blockscipy")],
    cmdclass={"build_ext": CMakeBuild},
    zip_safe=False,
)
```

And a minimal `CMakeLists.txt`:

```cmake
# --------------------------------------------------------------
#  CMakeLists.txt
# --------------------------------------------------------------
cmake_minimum_required(VERSION 3.14)
project(blockscipy LANGUAGES CXX)

find_package(Python COMPONENTS Interpreter Development REQUIRED)
find_package(pybind11 CONFIG REQUIRED)

add_library(blockscipy MODULE bindings.cpp)
target_link_libraries(blockscipy PRIVATE pybind11::module)

# Ensure the extension has the right suffix (e.g. .so, .pyd)
set_target_properties(blockscipy PROPERTIES
    PREFIX ""
    SUFFIX "${PYTHON_MODULE_EXTENSION}"
)
```

Now build and install:

```bash
$ pip install .
```

You will get a `blockscipy` package with the API shown in section 1.

